const inputItems = $input.all();

const preferredKeys = [
  'Веб-сайт 1',
  'Веб-сайт 2',
  'Веб-сайт 3',
  '2GIS URL',
  'Website 1',
  'Website 2',
  'Website 3',
  'Website',
  'Site 1',
  'Site 2',
  'Site 3',
  'Site',
  'URL',
  'Url',
  'url'
];

const clean = (value) => String(value ?? '').trim();

const looksLikeUrl = (value) => {
  const v = clean(value);
  if (!v) return false;
  if (/^mailto:/i.test(v)) return false;
  if (/^https?:\/\//i.test(v)) return true;
  return /^[a-z0-9.-]+\.[a-z]{2,}(?:[\/?#].*)?$/i.test(v);
};

const normalizeUrl = (value) => {
  let v = clean(value);
  if (!v) return '';

  if (!/^https?:\/\//i.test(v)) {
    v = `https://${v.replace(/^\/+/,'')}`;
  }

  try {
    const parsed = new URL(v);
    if (!parsed.hostname || !parsed.hostname.includes('.')) return '';
    return parsed.toString();
  } catch (error) {
    return '';
  }
};

return inputItems.map((item) => {
  const row = item.json || {};
  let rawUrl = '';

  for (const key of preferredKeys) {
    if (Object.prototype.hasOwnProperty.call(row, key) && looksLikeUrl(row[key])) {
      rawUrl = row[key];
      break;
    }
  }

  if (!rawUrl) {
    for (const [key, value] of Object.entries(row)) {
      if (/(сайт|веб|website|site|url)/i.test(key) && looksLikeUrl(value)) {
        rawUrl = value;
        break;
      }
    }
  }

  if (!rawUrl) {
    for (const value of Object.values(row)) {
      if (looksLikeUrl(value)) {
        rawUrl = value;
        break;
      }
    }
  }

  const targetUrl = normalizeUrl(rawUrl);
  let targetHost = '';

  if (targetUrl) {
    try {
      targetHost = new URL(targetUrl).hostname.replace(/^www\./i, '').toLowerCase();
    } catch (error) {
      targetHost = '';
    }
  }

  item.json.targetUrl = targetUrl;
  item.json.targetHost = targetHost;
  item.json.url_detected = Boolean(targetUrl);
  return item;
});

const inputItems = $input.all();
const sourceItems = $items('Select URL', 0, $runIndex) || [];
const emailRegex = /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi;

const blockedDomains = [
  '2gis.ru',
  'wixpress.com',
  'sentry.io',
  'cloudflare.com',
  'example.com',
  'example.org',
  'example.net'
];

const blockedLocalStarts = ['noreply', 'no-reply', 'donotreply', 'do-not-reply'];

const normalizeEmail = (value) =>
  String(value)
    .toLowerCase()
    .replace(/^[\s"'<>()[\]{}.,;:!]+|[\s"'<>()[\]{}.,;:!]+$/g, '');

const isBlocked = (email) => {
  if (!email || !email.includes('@')) return true;

  const [local, domainRaw] = email.split('@');
  const domain = String(domainRaw || '').toLowerCase();
  const localPart = String(local || '').toLowerCase();

  if (!localPart || !domain) return true;
  if (blockedLocalStarts.some((prefix) => localPart.startsWith(prefix))) return true;

  return blockedDomains.some((blocked) => domain === blocked || domain.endsWith(`.${blocked}`));
};

return inputItems.map((item, idx) => {
  const paired = item.pairedItem;
  let sourceIndex = idx;

  if (typeof paired === 'number') {
    sourceIndex = paired;
  } else if (paired && typeof paired === 'object' && typeof paired.item === 'number') {
    sourceIndex = paired.item;
  } else if (Array.isArray(paired) && paired[0] && typeof paired[0].item === 'number') {
    sourceIndex = paired[0].item;
  }

  const sourceRow = sourceItems[sourceIndex]?.json || {};
  const mergedJson = { ...sourceRow, ...item.json };

  const htmlRaw = String(
    mergedJson.html ?? mergedJson.body ?? mergedJson.data ?? mergedJson.response ?? ''
  );

  const prepared = htmlRaw
    .replace(/<script\b[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style\b[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<!--([\s\S]*?)-->/g, ' ');

  const matches = prepared.match(emailRegex) || [];
  const deduped = [...new Set(matches.map(normalizeEmail).filter((email) => email && !isBlocked(email)))];

  mergedJson.emails_array = deduped;
  mergedJson.emails_string = deduped.join(', ');
  mergedJson.email_1 = deduped[0] || '';
  mergedJson.email_2 = deduped[1] || '';
  mergedJson.ID = mergedJson.ID ?? sourceRow.ID ?? '';

  const hasFetchError = Boolean(mergedJson.error);
  mergedJson.parse_status = deduped.length > 0
    ? 'emails_found'
    : hasFetchError
      ? 'fetch_error_or_no_email'
      : 'no_email_found';

  item.json = mergedJson;
  return item;
});

